const res = await fetch("https://idx.quantyralabs.cc/api/v1/search?dataset=stellar", {
  method: "POST",
  headers: {
    "Authorization": "Bearer ${process.env.IDX_API_TOKEN}",
    "Content-Type": "application/json",
    "X-Domain-Slug": "${process.env.IDX_DOMAIN_SLUG}"
  },
  body: JSON.stringify({
        "min_price": 250000,
        "min_beds": 2,
        "city": "Largo",
        "statuses": ["Active"],
        "low_risk_floodzone": true,
        "max_monthly_fees": 500,
        "page": { "limit": 24, "skip": 0 }
      }),
});
if (!res.ok) throw new Error(`API ${res.status}`);
const data = await res.json();
